<?php include __DIR__ . '/../includes/header.php'; $cart=$_SESSION['cart']??[]; $subtotal=0; ?><h1>Shopping Cart</h1><div class="checkout-layout"><section class="panel"><table class="table"><tr><th>Product</th><th>Price</th><th>Qty</th><th>Total</th><th>Action</th></tr><?php foreach($cart as $id=>$qty): $r=mysqli_query($conn,'SELECT * FROM products WHERE id='.(int)$id); if($p=mysqli_fetch_assoc($r)): $line=$p['price']*$qty; $subtotal+=$line; ?><tr><td><img src="<?= BASE_URL ?>assets/images/<?= e($p['image']) ?>"> <?= e($p['name']) ?></td><td>$<?= number_format((float)$p['price'],2) ?></td><td><?= (int)$qty ?></td><td>$<?= number_format((float)$line,2) ?></td><td><a href="<?= BASE_URL ?>cart/remove.php?id=<?= $id ?>">Remove</a></td></tr><?php endif; endforeach; ?><?php if(empty($cart)): ?><tr><td colspan="5">Your cart is empty.</td></tr><?php endif; ?></table></section><aside class="panel"><h3>Order Summary</h3><p>Subtotal: $<?= number_format($subtotal,2) ?></p><p>Shipping: Free</p><p>Tax 7%: $<?= number_format($subtotal*0.07,2) ?></p><div class="total"><span>Total</span><span>$<?= number_format($subtotal*1.07,2) ?></span></div><a class="btn" href="<?= BASE_URL ?>cart/checkout.php">Checkout</a><a class="btn secondary" href="<?= BASE_URL ?>products.php">Continue Shopping</a></aside></div><?php include __DIR__ . '/../includes/footer.php'; ?>